class Counter {
    private int count;

    public void increment() {
        count++;
    }

    public void decrement() {
        if (count > 0) {
            count--;
        }
    }

    public void reset() {
        count = 0;
    }

    public int getCount() {
        return count;
    }
}

public class App {
    public static void main(String[] args) {
        Counter c = new Counter();
        for (int i = 0; i < 5; i++) c.increment();
        for (int i = 0; i < 8; i++) c.decrement();
        System.out.println("Count: " + c.getCount());
    }
}

