class Employee {
    private final int id;
    private String name;
    private double salary;

    public Employee(int id, String name, double salary) {
        this.id = id;
        this.name = name;
        this.salary = salary;
    }

    public int getId() { return id; }
    public String getName() { return name; }
    public double getSalary() { return salary; }

    public void setName(String name) {
        if (name == null || name.isBlank()) {
            throw new IllegalArgumentException("Name cannot be empty");
        }
        this.name = name;
    }

    public void setSalary(double salary) {
        if (salary < 0) {
            throw new IllegalArgumentException("Salary cannot be negative");
        }
        this.salary = salary;
    }
}

public class App {
    public static void main(String[] args) {
        Employee e = new Employee(101, "Aisha", 75000);
        e.setSalary(85000);
        System.out.println("Employee #" + e.getId() + " " + e.getName() + " — ₹" + e.getSalary());
    }
}

class Circle {
    private final double radius;

    public Circle(double radius) {
        if (radius <= 0) throw new IllegalArgumentException("Radius must be positive");
        this.radius = radius;
    }

    public double getRadius() { return radius; }

    public double getArea() {
        return Math.PI * radius * radius;
    }

    public double getCircumference() {
        return 2 * Math.PI * radius;
    }
}

public class App {
    public static void main(String[] args) {
        Circle c = new Circle(5);
        System.out.println("Radius: " + c.getRadius());
        System.out.println("Area: " + c.getArea());
        System.out.println("Circumference: " + c.getCircumference());
    }
}

class Password {
    private String hashedValue;

    public Password(String plain) {
        this.hashedValue = hash(plain);
    }

    private String hash(String s) {
        return new StringBuilder(s).reverse().toString();
    }

    public boolean matches(String plainAttempt) {
        return hash(plainAttempt).equals(hashedValue);
    }
}

public class App {
    public static void main(String[] args) {
        Password pwd = new Password("secret123");
        System.out.println("Correct password? " + pwd.matches("secret123"));
        System.out.println("Wrong password? " + pwd.matches("wrong"));
    }
}

class BankAccount {
    private final int accountNumber;
    private String holderName;
    private double balance;

    public BankAccount(int accountNumber, String holderName, double balance) {
        if (accountNumber <= 0) throw new IllegalArgumentException("Account number must be positive");
        if (holderName == null || holderName.isBlank()) throw new IllegalArgumentException("Name required");
        if (balance < 0) throw new IllegalArgumentException("Initial balance cannot be negative");
        this.accountNumber = accountNumber;
        this.holderName = holderName;
        this.balance = balance;
    }

    public int getAccountNumber() { return accountNumber; }
    public String getHolderName() { return holderName; }
    public double getBalance() { return balance; }

    public void setHolderName(String holderName) {
        if (holderName == null || holderName.isBlank()) throw new IllegalArgumentException("Name required");
        this.holderName = holderName;
    }

    public void deposit(double amount) {
        if (amount <= 0) throw new IllegalArgumentException("Deposit must be positive");
        balance += amount;
    }

    public void withdraw(double amount) {
        if (amount <= 0) throw new IllegalArgumentException("Withdrawal must be positive");
        if (amount > balance) throw new IllegalArgumentException("Insufficient funds");
        balance -= amount;
    }
}

public class App {
    public static void main(String[] args) {
        BankAccount acc = new BankAccount(1001, "Aisha", 5000);
        acc.deposit(2000);
        acc.withdraw(1500);

        try {
            acc.withdraw(10000);
        } catch (IllegalArgumentException e) {
            // Silently caught - expected to fail
        }

        System.out.println("Account #" + acc.getAccountNumber() + " " + acc.getHolderName() + " — ₹" + acc.getBalance());
    }
}

class URL {
    private final String protocol;
    private final String host;
    private final String path;

    public URL(String protocol, String host, String path) {
        this.protocol = protocol == null ? "" : protocol;
        this.host = host == null ? "" : host;
        this.path = path == null ? "" : path;
    }

    public String getProtocol() { return protocol; }
    public String getHost() { return host; }
    public String getPath() { return path; }

    public URL withProtocol(String p) {
        return new URL(p, host, path);
    }

    public URL withHost(String h) {
        return new URL(protocol, h, path);
    }

    public URL withPath(String p) {
        return new URL(protocol, host, p);
    }

    public String toUrl() {
        return protocol + "://" + host + path;
    }
}

public class App {
    public static void main(String[] args) {
        URL original = new URL("https", "google.com", "/");
        URL modified = original.withPath("/search").withHost("bing.com");

        System.out.println("Original: " + original.toUrl());
        System.out.println("Modified: " + modified.toUrl());
    }
}
